external_knowledge:
; Size labels refer to labels such as 'Small', 'Medium', etc.; 
; 'Active' sizes are those with 'active' status set to 1; 
; 'Reviewed' sizes are those with 'approved' reviews.

sql:
SELECT s.size_label, s.size_code
FROM sizes s
JOIN size_reviews sr ON s.size_id = sr.size_id
WHERE sr.rating = (
    SELECT MAX(rating) FROM size_reviews
);

SELECT COUNT(review_id) AS review_count
FROM size_reviews
WHERE size_id = 0;
